export const getUrl = (filename) => {
    const url = new URL(import.meta.url);
    const pathname = url.pathname;
    const directory = pathname.substring(0, pathname.lastIndexOf('/') + 1);
    return url.origin + directory + filename;
};
export const getWidgetId = () => {
    const regex = /widget\/(.*?)\//;
    const match = import.meta.url.match(regex);
    return (match && match[1]) || '';
};
export const getOrigin = () => {
    const url = new URL(import.meta.url);
    return url.origin;
};
